"""matplotlib.offsetbox — offset box classes for annotations."""

from matplotlib.artist import Artist


class OffsetBox(Artist):
    def __init__(self, *args, **kwargs):
        super().__init__()

    def get_extent(self, renderer): return (0, 0, 0, 0)
    def get_window_extent(self, renderer=None): return None
    def set_offset(self, xy): pass
    def get_offset(self, width=0, height=0, xdescent=0, ydescent=0, renderer=None): return (0, 0)


class PackerBase(OffsetBox):
    def __init__(self, pad=0, sep=0, width=None, height=None, align='baseline',
                 mode='fixed', children=None):
        super().__init__()
        self.pad = pad
        self.sep = sep


class VPacker(PackerBase):
    pass


class HPacker(PackerBase):
    pass


class PaddedBox(OffsetBox):
    def __init__(self, child, pad=0, *, draw_frame=False, patch_attrs=None):
        super().__init__()
        self.child = child
        self.pad = pad


class DrawingArea(OffsetBox):
    def __init__(self, width, height, xdescent=0, ydescent=0, clip=True):
        super().__init__()
        self.width = width
        self.height = height

    def add_artist(self, a): pass


class TextArea(OffsetBox):
    def __init__(self, s, *, textprops=None, multilinebaseline=False):
        super().__init__()
        self._text = s

    def get_text(self): return self._text
    def set_text(self, s): self._text = s


class AnnotationBbox(Artist):
    def __init__(self, offsetbox, xy, xybox=None, xycoords='data',
                 boxcoords=None, frameon=True, pad=0.4, annotation_clip=None,
                 box_alignment=(0.5, 0.5), bboxprops=None, arrowprops=None, **kwargs):
        super().__init__()
        self.offsetbox = offsetbox
        self.xy = xy
        self.xybox = xybox


class AnchoredOffsetbox(OffsetBox):
    def __init__(self, loc, *, pad=0.4, borderpad=0.5, child=None,
                 prop=None, frameon=True, bbox_to_anchor=None, bbox_transform=None):
        super().__init__()
        self.loc = loc


class AnchoredText(AnchoredOffsetbox):
    def __init__(self, s, loc, *, pad=0.4, borderpad=0.5, prop=None, **kwargs):
        super().__init__(loc, pad=pad, borderpad=borderpad)
        self.txt = TextArea(s, textprops=prop)


class OffsetImage(OffsetBox):
    def __init__(self, arr, *, zoom=1, cmap=None, norm=None, interpolation=None,
                 origin=None, filternorm=True, filterrad=4.0, resample=False,
                 dpi_cor=True, **kwargs):
        super().__init__()
        self.image = arr
        self.zoom = zoom
